import React, { useContext, useState } from "react";
import "./PlaceOrder.css";
import { StoreContext } from "../../Context/StoreContext";
import axios from 'axios';

const PlaceOrder = () => {
  const { getTotalCartAmount, cartItem, token } = useContext(StoreContext);

  const [data, setData] = useState({
    firstname: "",
    lastname: "",
    email: "",
    street: "",
    city: "",
    state: "",
    zipcode: "",
    country: "",
    phone: "",
  });

  const onChangehandler = (event) => {
    const name = event.target.name;
    const value = event.target.value;
    setData((data) => ({ ...data, [name]: value }));
  };

  const handlePayment = async () => {
    try {
      const orderDetails = {
        cartItems: cartItem,
        totalAmount: getTotalCartAmount() + 50, // Including delivery fee
        customerData: data,
      };

      const response = await axios.post('http://localhost:4000/api/payment/create-order', orderDetails, {
        headers: { token }
      });

      if (response.data.status === 'success') {
        window.location.href = response.data.paymentUrl; // Redirect to Cashfree payment URL
      } else {
        alert("Payment initiation failed");
      }
    } catch (error) {
      console.error("Error initiating payment", error);
      alert("An error occurred while processing payment.");
    }
  };

  return (
    <form className="placeorder">
      <div className="place-order-left">
        <p className="title">Delivery Information</p>
        {/* Existing form fields */}
      </div>
      <div className="place-order-right">
        <div className="cart-total">
          <h2>Cart Total</h2>
          <div>
            <div className="cart-total-details">
              <p>SubTotal</p>
              <p>₹{getTotalCartAmount()}</p>
            </div>
            <hr />
            <div className="cart-total-details">
              <p>Delivery Fee</p>
              <p>₹{getTotalCartAmount() === 0 ? 0 : 50}</p>
            </div>
            <hr />
            <div className="cart-total-details">
              <b>Total</b>
              <b>₹{getTotalCartAmount() === 0 ? 0 : getTotalCartAmount() + 50}</b>
            </div>
          </div>
          <button type="button" onClick={handlePayment}>PROCEED TO PAYMENT</button>
        </div>
      </div>
    </form>
  );
};

export default PlaceOrder;
